// 1. Sətir siyahısı
let names: string[] = ["Shirt", "Jacket", "Hat"];
// names = [42]; // Xəta: rəqəm sətir siyahısına əlavə edilə bilməz

// 2. Rəqəm siyahısı
let prices: Array<number> = [50, 100, 25];

// 3. Obyekt siyahısı
interface Item {
  name: string;
  price: number;
}
let items: Item[] = [
  { name: "Shirt", price: 50 },
  { name: "Jacket", price: 100 }
];

// 4. Funksiya ilə siyahı işlənməsi
function getFirstItem<T>(list: T[]): T | undefined {
  return list.length > 0 ? list[0] : undefined;
}
const firstName: string | undefined = getFirstItem(names);

// 5. fetch ilə siyahı sorğusu
async function fetchItems(): Promise<Item[] | null> {
  try {
    const response = await fetch("https://api.example.com/items");
    if (!response.ok) throw new Error("Şəbəkə xətası");
    const data: Item[] = await response.json();
    return data;
  } catch (error) {
    console.error("Xəta:", error);
    return null;
  }
}

